import { KeyStore } from "../lib/byok"
import { CollectionContextWidget } from "./widgets/CollectionContextWidget"
import { SourcesWidget, type DataSource } from "./widgets/SourcesWidget"
import { NarrativeRenderer } from "./NarrativeRenderer"
import type { ChronicleResponse, MentionProviderDebug, SocialSignalProvider } from "../lib/types"
import type { SynthesisPhase } from "../lib/byok/useSynthesize"
import type { SynthesisMode } from "../lib/byok/context"

interface Props {
  chronicle: ChronicleResponse
  narrative: string | null
  streamingText: string
  phase: SynthesisPhase
  elapsed: number
  synthError: string | null
  lastInputMode: SynthesisMode | null
  researchLogs: any[]
  onSynthesize: () => void
  onOpenBYOK: () => void
  onCancel: () => void
}

export function ChronicleCard({
  chronicle,
  narrative,
  streamingText,
  phase,
  elapsed,
  synthError,
  lastInputMode,
  researchLogs,
  onSynthesize,
  onOpenBYOK,
  onCancel,
}: Props) {
  const hasKey = KeyStore.has()
  const config = KeyStore.get()

  // Built data sources from chronicle response metadata
  const sources = buildDataSources(chronicle)

  return (
    <div className="chronicle-card glass-card">
      <CollectionContextWidget collectionContext={chronicle.collection_context} />
      <CollectorSignalsPanel chronicle={chronicle} />
      {chronicle.debug_info?.mention_providers && (
        <details style={{ marginBottom: "var(--space-md)" }}>
          <summary style={{ cursor: "pointer", fontWeight: 700, marginBottom: "0.5rem" }}>
            Collector signals debug
          </summary>
          <CollectorSignalsDebug debugInfo={chronicle.debug_info.mention_providers} />
        </details>
      )}
      {!narrative && !hasKey && (
        <p className="chronicle-card-hint" style={{ marginBottom: "var(--space-md)" }}>
          🔑 Set your API key to generate narratives
        </p>
      )}
      <NarrativeRenderer
        narrative={narrative}
        streamingText={streamingText}
        phase={phase}
        elapsed={elapsed}
        providerName={config?.provider}
        modelName={config?.model}
        error={synthError}
        inputMode={lastInputMode}
        researchLogs={researchLogs}
        onGenerate={hasKey ? onSynthesize : onOpenBYOK}
        actionLabel={hasKey ? "✨ Generative Chronicle" : "🔑 Configure BYOK"}
        emptyMessage={
          hasKey
            ? "Generate an AI-powered Chronicle narrative from the factual timeline above."
            : "Unlock the client-side Generative Chronicle with your BYOK key. The factual timeline remains available without it."
        }
        onCancel={onCancel}
      />

      {/* Sources Widget */}
      <div style={{ marginTop: "auto" }}>
        <SourcesWidget sources={sources} />
      </div>
    </div>
  )
}

function CollectorSignalsPanel({ chronicle }: { chronicle: ChronicleResponse }) {
  const { collector_signals: signals } = chronicle
  const dominantScope = signals.scope_breakdown.dominant_scope
  const scopeLabel = dominantScope === "collection_level"
    ? "Collection-level"
    : dominantScope === "mixed"
      ? "Mixed"
      : dominantScope === "inscription_level"
        ? "Inscription-level"
        : "No social scope"

  const trendsMention = chronicle.events.find(
    (e) => e.event_type === "social_mention" && e.payload.provider === "google_trends"
  )

  return (
    <section
      style={{
        marginBottom: "var(--space-md)",
        padding: "0.85rem 0.95rem",
        borderRadius: "var(--radius-lg)",
        border: "1px solid var(--border-subtle)",
        background: "var(--bg-glass)",
      }}
    >
      <div style={{ display: "flex", justifyContent: "space-between", gap: "1rem", marginBottom: "0.5rem" }}>
        <strong>Collector Signals</strong>
        <span style={{ color: "var(--text-secondary)", fontSize: "0.85rem" }}>
          Attention {signals.attention_score}/100
        </span>
      </div>
      <div style={{ fontSize: "0.9rem", display: "grid", gap: "0.35rem" }}>
        <div>
          Sentiment: <strong>{formatSentiment(signals.sentiment_label)}</strong>
          {" · "}
          Confidence: <strong>{signals.confidence}</strong>
        </div>
        <div>
          Scope: <strong>{scopeLabel}</strong>
          {" · "}
          Evidence: <strong>{signals.evidence_count}</strong>
        </div>
        {signals.sentiment_label === "insufficient_data" && (
          <div style={{ color: "var(--text-secondary)" }}>
            Not enough cross-source evidence yet
          </div>
        )}
        {signals.top_evidence.length > 0 && (
          <div style={{ display: "grid", gap: "0.35rem", marginTop: "0.25rem" }}>
            {signals.top_evidence.slice(0, 3).map((evidence) => (
              <a
                key={`${evidence.provider}:${evidence.url}`}
                href={evidence.url}
                target="_blank"
                rel="noopener noreferrer"
                style={{ color: "var(--text-secondary)", textDecoration: "none" }}
              >
                [{platformLabel(evidence.platform)}] {evidence.title}
              </a>
            ))}
          </div>
        )}
        {trendsMention && (
          <div style={{ marginTop: "0.25rem", padding: "0.5rem", background: "rgba(255,255,255,0.03)", borderRadius: "var(--radius-sm)", border: "1px solid var(--border-subtle)" }}>
            <div style={{ fontWeight: 600, marginBottom: "0.25rem" }}>Google Trends</div>
            <div style={{ whiteSpace: "pre-wrap", color: "var(--text-secondary)", fontSize: "0.85rem", lineHeight: 1.4 }}>
              {trendsMention.payload.text}
            </div>
          </div>
        )}
      </div>
    </section>
  )
}

function CollectorSignalsDebug({
  debugInfo,
}: {
  debugInfo: NonNullable<ChronicleResponse["debug_info"]>["mention_providers"]
}) {
  return (
    <div style={{ fontSize: "0.82rem", color: "var(--text-secondary)", display: "grid", gap: "0.75rem" }}>
      {Object.entries(debugInfo ?? {}).map(([provider, debug]) => (
        <ProviderDebugBlock
          key={provider}
          provider={provider as SocialSignalProvider}
          debug={debug as MentionProviderDebug}
        />
      ))}
    </div>
  )
}

function ProviderDebugBlock({
  provider,
  debug,
}: {
  provider: SocialSignalProvider
  debug: MentionProviderDebug
}) {
  return (
    <div style={{ display: "grid", gap: "0.35rem" }}>
      <div><strong>{providerLabel(provider)}</strong></div>
      <div>Collection: {debug.collection_name ?? "unknown"}</div>
      <div>Item: {debug.item_name ?? "unknown"}</div>
      {debug.official_x_urls && (
        <div>Seed profiles: {debug.official_x_urls.length > 0 ? debug.official_x_urls.join(", ") : "none"}</div>
      )}
      {debug.candidate_handles && (
        <div>Candidate handles: {debug.candidate_handles.length > 0 ? debug.candidate_handles.join(", ") : "none"}</div>
      )}
      <div>Queries:</div>
      {debug.queries.map((query) => (
        <code key={`${provider}-${query}`} style={{ whiteSpace: "pre-wrap" }}>{query}</code>
      ))}
      <div>Attempts:</div>
      {debug.attempts.map((attempt, index) => (
        <code key={`${provider}-${attempt.query}-${index}`} style={{ whiteSpace: "pre-wrap" }}>
          {attempt.target ? `${attempt.target} · ` : ""}
          {attempt.outcome} · {attempt.status ?? "-"} · {attempt.result_count ?? 0} · {attempt.query}
        </code>
      ))}
      {debug.notes.map((note, index) => (
        <code key={`${provider}-note-${index}`} style={{ whiteSpace: "pre-wrap" }}>
          note · {note}
        </code>
      ))}
    </div>
  )
}

// --- Data source builder ---

function buildDataSources(chronicle: ChronicleResponse): DataSource[] {
  const sources: DataSource[] = []
  const events = chronicle.events
  const sourceCatalog = chronicle.source_catalog
  const protocolEntries = sourceCatalog.filter(
    (source) => source.trust_level === "canonical_onchain" || source.trust_level === "official_index"
  )
  const registryEntries = sourceCatalog.filter(
    (source) => source.trust_level === "curated_public_registry"
  )
  const marketEntries = sourceCatalog.filter(
    (source) => source.trust_level === "market_overlay"
  )
  const mempoolEntries = sourceCatalog.filter(
    (source) => source.trust_level === "bitcoin_indexer"
  )
  const socialEntries = sourceCatalog.filter(
    (source) => source.trust_level === "public_social"
  )

  // ordinals.com — always queried for metadata
  sources.push({
    name: "ordinals.com",
    status: protocolEntries.some((entry) => !entry.partial)
      ? "success"
      : protocolEntries.length > 0
        ? "partial"
        : chronicle.meta.inscription_id
          ? "success"
          : "failed",
    detail: (chronicle.collection_context.presentation.full_label ?? chronicle.collection_context.presentation.item_label ?? chronicle.collection_context.presentation.primary_label)
      ? `Metadata + provenance for ${chronicle.collection_context.presentation.full_label ?? chronicle.collection_context.presentation.item_label ?? chronicle.collection_context.presentation.primary_label}`
      : "Inscription metadata and protocol provenance",
    cached: chronicle.from_cache,
    count: protocolEntries.length > 0 ? protocolEntries.length : 1,
    links: [
      { label: "Inscription", url: `https://ordinals.com/inscription/${chronicle.meta.inscription_id}` },
      ...protocolEntries.map((entry) => ({ label: entry.source_type, url: entry.url_or_ref }))
    ]
  })

  // mempool.space — transfers
  const transferCount = events.filter(
    (e) => e.event_type === "transfer" || e.event_type === "sale"
  ).length
  sources.push({
    name: "mempool.space",
    status: mempoolEntries.some((entry) => !entry.partial) ? "success" : "partial",
    detail: transferCount > 0
      ? `${transferCount} transfer${transferCount > 1 ? "s" : ""} found`
      : mempoolEntries.length > 0
        ? "Genesis and current output checked"
        : "No transfers detected",
    cached: chronicle.from_cache,
    count: mempoolEntries.length > 0 ? mempoolEntries.length : transferCount,
    links: [
      ...mempoolEntries.map((entry) => ({ label: entry.source_type, url: entry.url_or_ref })),
      ...events
      .filter((e) => e.event_type === "transfer" || e.event_type === "sale")
      .map((e) => ({
        label: `${e.event_type} tx`,
        url: e.source.ref.startsWith("http") ? e.source.ref : `https://mempool.space/tx/${e.source.ref.split(":")[0]}`
      }))
    ]
  })

  const mentionCount = events.filter((e) => e.event_type === "social_mention").length
  const collectorSignals = chronicle.collector_signals
  sources.push({
    name: "Collector signals",
    status: mentionCount > 0 ? "success" : "partial",
    detail: mentionCount > 0
      ? `${mentionCount} mention${mentionCount > 1 ? "s" : ""} found · ${formatSentiment(collectorSignals.sentiment_label)}`
      : "Not enough cross-source evidence yet",
    cached: chronicle.from_cache,
    count: mentionCount,
    links: [
      ...events
        .filter((e) => e.event_type === "social_mention")
        .map((e, i) => ({
          label: e.description ? (e.description.length > 30 ? e.description.substring(0, 30) + "..." : e.description) : `Mention ${i + 1}`,
          url: e.source.ref
        })),
      ...socialEntries.map((entry) => ({
        label: entry.source_type,
        url: entry.url_or_ref,
      })),
    ]
  })

  if (registryEntries.length > 0) {
    sources.push({
      name: "ordinals-collections",
      status: registryEntries.some((entry) => !entry.partial) ? "success" : "partial",
      detail: chronicle.collection_context.registry.match
        ? `${chronicle.collection_context.registry.match.matched_collection} · ${chronicle.collection_context.registry.match.quality_state}`
        : "Curated collection overlay",
      cached: chronicle.from_cache,
      count: registryEntries.length,
      links: registryEntries.map((e) => ({ label: e.source_type, url: e.url_or_ref }))
    })
  }

  if (marketEntries.length > 0) {
    const marketMatch = chronicle.collection_context.market.match
    const isSatflowSource = marketMatch?.source_ref.includes("satflow.com")
    const marketSourceName = isSatflowSource ? "satflow.com" : "ord.net"
    const rarityOverlay = marketMatch?.rarity_overlay
    const rarityDetail = rarityOverlay
      ? ` · ${rarityOverlay.source === "satflow" ? "Satflow" : "ord.net"} rarity · ${rarityOverlay.traits.length} traits`
      : ""
    sources.push({
      name: marketSourceName,
      status: marketEntries.some((entry) => !entry.partial) ? "success" : "partial",
      detail: marketMatch
        ? `${marketMatch.collection_name} · ${marketMatch.verified ? "verified" : "overlay"}${rarityDetail}`
        : "Public market overlay",
      cached: chronicle.from_cache,
      count: marketEntries.length,
      links: marketEntries.map((e) => ({ label: e.source_type, url: e.url_or_ref }))
    })
  }

  // UniSat enrichment
  const unisatEntries = sourceCatalog.filter(
    (source) => source.trust_level === "unisat_indexer"
  )
  if (unisatEntries.length > 0) {
    sources.push({
      name: "unisat.io",
      status: unisatEntries.some((entry) => !entry.partial) ? "success" : "partial",
      detail: "Indexer inscription data",
      cached: chronicle.from_cache,
      count: unisatEntries.length,
      links: unisatEntries.map((e) => ({ label: e.source_type, url: e.url_or_ref }))
    })
  }

  return sources
}

function formatSentiment(sentiment: ChronicleResponse["collector_signals"]["sentiment_label"]): string {
  if (sentiment === "insufficient_data") return "Insufficient data"
  return sentiment.charAt(0).toUpperCase() + sentiment.slice(1)
}

function platformLabel(platform: ChronicleResponse["collector_signals"]["top_evidence"][number]["platform"]): string {
  switch (platform) {
    case "nostr":
      return "Nostr"
    case "x":
      return "X"
    case "google_trends":
      return "Trends"
    default:
      return "Social"
  }
}

function providerLabel(provider: SocialSignalProvider): string {
  switch (provider) {
    case "google_trends":
      return "Google Trends"
    default:
      return provider.charAt(0).toUpperCase() + provider.slice(1)
  }
}

import { useEffect, useRef, useState } from "react"
import { getMediaPreviewMode } from "../lib/media"
import { SatRarityBadge, CharmBadge } from "./SatBadge"
import type { ChronicleResponse } from "../lib/types"

interface Props {
  chronicle: ChronicleResponse
}

const MAX_TEXT_PREVIEW_BYTES = 24 * 1024

export function InscriptionPreview({ chronicle }: Props) {
  const { meta, media_context } = chronicle
  const previewMode = getMediaPreviewMode(media_context)
  const previewSandbox = media_context.preview_url.startsWith("https://ordinals.com/preview/")
    ? "allow-scripts allow-same-origin"
    : "allow-scripts"
  const [renderFallback, setRenderFallback] = useState(false)
  const [isDragging, setIsDragging] = useState(false)
  const containerRef = useRef<HTMLDivElement>(null)
  const imgRef = useRef<HTMLImageElement>(null)
  const isInteractiveImage = previewMode === "image" && !renderFallback

  useEffect(() => {
    setRenderFallback(false)
    setIsDragging(false)
  }, [meta.inscription_id, previewMode])

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!isInteractiveImage || !containerRef.current || !imgRef.current) return

    const rect = containerRef.current.getBoundingClientRect()
    const x = e.clientX - rect.left
    const y = e.clientY - rect.top
    const centerX = rect.width / 2
    const centerY = rect.height / 2

    let rotateX = ((y - centerY) / centerY) * -15
    let rotateY = ((x - centerX) / centerX) * 15
    let scale = 1.05
    let skewX = 0
    let skewY = 0

    if (isDragging) {
      rotateX *= 2.5
      rotateY *= 2.5
      scale = 0.95
      skewX = (x - centerX) / 20
      skewY = (y - centerY) / 20
      imgRef.current.style.transition = "transform 0.05s linear"
    } else {
      imgRef.current.style.transition = "transform 0.1s ease-out"
    }

    imgRef.current.style.transform = `
      rotateX(${rotateX}deg)
      rotateY(${rotateY}deg)
      scale(${scale})
      skew(${skewX}deg, ${skewY}deg)
    `

    imgRef.current.style.filter = isDragging
      ? `brightness(${1 + Math.abs(rotateX + rotateY) / 1000}) contrast(1.1)`
      : "none"

    const px = (x / rect.width) * 100
    const py = (y / rect.height) * 100
    containerRef.current.style.setProperty("--mouse-x", `${px}%`)
    containerRef.current.style.setProperty("--mouse-y", `${py}%`)
  }

  const resetTransform = () => {
    if (!imgRef.current) return

    imgRef.current.style.transition =
      "transform 0.6s cubic-bezier(0.34, 1.56, 0.64, 1), filter 0.3s ease"
    imgRef.current.style.transform =
      "rotateX(0deg) rotateY(0deg) scale(1) skew(0deg, 0deg)"
    imgRef.current.style.filter = "none"
  }

  return (
    <div
      className={[
        "chronicle-card-content-preview",
        isInteractiveImage ? "is-interactive" : "",
        previewMode === "text" && !renderFallback ? "is-text" : "",
      ]
        .filter(Boolean)
        .join(" ")}
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseDown={isInteractiveImage ? () => setIsDragging(true) : undefined}
      onMouseUp={
        isInteractiveImage
          ? () => {
              setIsDragging(false)
              resetTransform()
            }
          : undefined
      }
      onMouseLeave={
        isInteractiveImage
          ? () => {
              setIsDragging(false)
              resetTransform()
            }
          : undefined
      }
    >
      {renderFallback || previewMode === "ordinals_preview" ? (
        <iframe
          title={`Inscription #${meta.inscription_number} preview`}
          src={media_context.preview_url}
          loading="lazy"
          sandbox={previewSandbox}
          referrerPolicy="no-referrer"
        />
      ) : previewMode === "audio" ? (
        <audio
          controls
          preload="metadata"
          src={media_context.content_url}
          onError={() => setRenderFallback(true)}
        />
      ) : previewMode === "video" ? (
        <video
          controls
          playsInline
          preload="metadata"
          src={media_context.content_url}
          onError={() => setRenderFallback(true)}
        />
      ) : previewMode === "text" ? (
        <TextPreview
          contentType={media_context.content_type}
          contentUrl={media_context.content_url}
          onFallback={setRenderFallback}
        />
      ) : (
        <img
          ref={imgRef}
          src={media_context.content_url}
          alt={`Inscription #${meta.inscription_number}`}
          loading="lazy"
          onError={() => setRenderFallback(true)}
        />
      )}

      {/* Sat rarity & charm badges — overlaid on preview */}
      {(meta.sat_rarity !== "common" || (meta.charms && meta.charms.length > 0)) && (
        <div className="sat-rarity-overlay">
          <SatRarityBadge rarity={meta.sat_rarity} />
          {meta.charms?.map(charm => (
            <CharmBadge key={charm} charm={charm} />
          ))}
        </div>
      )}
    </div>
  )
}

function TextPreview({
  contentType,
  contentUrl,
  onFallback,
}: {
  contentType: string
  contentUrl: string
  onFallback: (value: boolean) => void
}) {
  const [state, setState] = useState<{
    status: "loading" | "ready"
    text: string
    truncated: boolean
  }>({
    status: "loading",
    text: "",
    truncated: false,
  })

  useEffect(() => {
    const controller = new AbortController()

    void (async () => {
      try {
        const res = await fetch(contentUrl, {
          signal: controller.signal,
          cache: "force-cache",
        })

        if (!res.ok) {
          onFallback(true)
          return
        }

        const preview = await readTextPreview(res, MAX_TEXT_PREVIEW_BYTES)
        if (!preview.text.trim()) {
          onFallback(true)
          return
        }

        setState({
          status: "ready",
          text: preview.text,
          truncated: preview.truncated,
        })
      } catch (error) {
        if ((error as DOMException).name !== "AbortError") {
          onFallback(true)
        }
      }
    })()

    return () => {
      controller.abort()
    }
  }, [contentUrl, onFallback])

  if (state.status === "loading") {
    return (
      <div className="chronicle-card-preview-placeholder">
        Loading inscription text preview…
      </div>
    )
  }

  return (
    <div className="chronicle-card-text-preview">
      <pre>{state.text}</pre>
      <div className="chronicle-card-text-meta">
        <span>{contentType}</span>
        {state.truncated ? <span>Preview truncated for performance</span> : null}
      </div>
    </div>
  )
}

async function readTextPreview(
  res: Response,
  maxBytes: number
): Promise<{ text: string; truncated: boolean }> {
  if (!res.body) {
    const text = await res.text()
    return {
      text: text.slice(0, maxBytes),
      truncated: text.length > maxBytes,
    }
  }

  const reader = res.body.getReader()
  const chunks: Uint8Array[] = []
  let totalBytes = 0
  let truncated = false

  while (true) {
    const { done, value } = await reader.read()
    if (done) break
    if (!value) continue

    const remaining = maxBytes - totalBytes
    if (remaining <= 0) {
      truncated = true
      await reader.cancel()
      break
    }

    if (value.byteLength > remaining) {
      chunks.push(value.subarray(0, remaining))
      totalBytes += remaining
      truncated = true
      await reader.cancel()
      break
    }

    chunks.push(value)
    totalBytes += value.byteLength
  }

  const merged = new Uint8Array(totalBytes)
  let offset = 0
  for (const chunk of chunks) {
    merged.set(chunk, offset)
    offset += chunk.byteLength
  }

  return {
    text: new TextDecoder().decode(merged),
    truncated,
  }
}

// Rarity & Traits Widget — displays trait-based rarity data from the merged factual pipeline.
// Shows: rank headline, trait breakdown with frequency bars, data confidence indicator.
// Refactored to match InscriptionMetaWidget grid style.

import { useEffect, useMemo, useState } from "react"
import type { UnisatEnrichment, DataValidationResult, TraitRarityBreakdown } from "../../lib/types"

interface Props {
  unisatEnrichment?: UnisatEnrichment
  validation?: DataValidationResult
}

export function RarityWidget({ unisatEnrichment, validation }: Props) {
  const rarity = unisatEnrichment?.rarity
  if (!rarity || rarity.traits.length === 0) return null

  const TRAITS_PER_PAGE = 6
  const traitItems: TraitRarityBreakdown[] = rarity.trait_breakdown.length > 0
    ? rarity.trait_breakdown
    : rarity.traits.map((trait) => ({
        trait_type: trait.trait_type,
        value: trait.value,
        frequency: undefined,
        frequency_pct: undefined,
        rarity_contribution: undefined,
      }))
  const totalPages = Math.max(1, Math.ceil(traitItems.length / TRAITS_PER_PAGE))
  const [currentPage, setCurrentPage] = useState(0)

  useEffect(() => {
    setCurrentPage((page) => Math.min(page, totalPages - 1))
  }, [totalPages])

  const visibleTraits = useMemo(() => {
    const start = currentPage * TRAITS_PER_PAGE
    return traitItems.slice(start, start + TRAITS_PER_PAGE)
  }, [currentPage, traitItems])

  const traitSlots = useMemo(() => {
    const slots: Array<(typeof visibleTraits)[number] | null> = [...visibleTraits]
    while (slots.length < TRAITS_PER_PAGE) {
      slots.push(null)
    }
    return slots
  }, [visibleTraits])

  const confidenceIcon = validation
    ? validation.confidence === "high" ? "✓" : validation.confidence === "medium" ? "⚠" : "✗"
    : null

  const confidenceLabel = validation
    ? {
        high: "Sources corroborated",
        medium: "Partial corroboration",
        low: "Data discrepancies detected",
      }[validation.confidence]
    : null

  const agreeing = validation
    ? validation.checks.filter(c => c.sources_agree).length
    : 0
  const total = validation?.checks.length ?? 0

  return (
    <div className="widget-rarity-grid-wrapper">
      <div className="widget-rarity-grid-header">
        <div className="widget-rarity-grid-label">Traits & Attributes</div>
        {totalPages > 1 && (
          <div className="widget-rarity-pagination" aria-label="Traits pagination">
            <button
              type="button"
              className="widget-rarity-page-btn"
              aria-label="Previous traits page"
              onClick={() => setCurrentPage((page) => Math.max(0, page - 1))}
              disabled={currentPage === 0}
            >
              ←
            </button>
            <span className="widget-rarity-page-indicator">
              {currentPage + 1}/{totalPages}
            </span>
            <button
              type="button"
              className="widget-rarity-page-btn"
              aria-label="Next traits page"
              onClick={() => setCurrentPage((page) => Math.min(totalPages - 1, page + 1))}
              disabled={currentPage === totalPages - 1}
            >
              →
            </button>
          </div>
        )}
      </div>

      {!!rarity.rarity_rank && (
        <div className="widget-meta-cell widget-rarity-rank-cell">
          <span className="widget-meta-label">Rarity Rank</span>
          <span className="widget-meta-value">#{rarity.rarity_rank.toLocaleString("en-US")}</span>
          <span className="widget-meta-sub">
            of {rarity.total_supply?.toLocaleString("en-US") ?? "—"} {rarity.rarity_percentile ? `· top ${rarity.rarity_percentile}%` : ""}
          </span>
        </div>
      )}

      <div className="widget-meta-grid widget-rarity-traits-grid">
        {traitSlots.map((trait, index) => (
          <div
            key={trait ? `${trait.trait_type}-${trait.value}` : `empty-${currentPage}-${index}`}
            className={`widget-meta-cell ${trait ? "" : "widget-meta-cell-empty"}`.trim()}
            aria-hidden={!trait}
          >
            {trait ? (
              <>
                <span className="widget-meta-label">{trait.trait_type}</span>
                <span className="widget-meta-value">{trait.value}</span>
                {trait.frequency_pct !== undefined && (
                  <span className="widget-meta-sub">
                    {trait.frequency_pct < 1
                      ? `${trait.frequency_pct.toFixed(2)}%`
                      : `${Math.round(trait.frequency_pct)}%`} freq
                  </span>
                )}
              </>
            ) : null}
          </div>
        ))}
      </div>

      {/* Footer Info (Validation & Source) */}
      <div className="widget-rarity-grid-footer">
        {validation && (
          <div className={`widget-rarity-confidence-mini tone-${validation.confidence}`}>
            {confidenceIcon} {confidenceLabel} · {agreeing}/{total}
          </div>
        )}
        <div className="widget-rarity-source-mini">
          via public metadata and market overlays
        </div>
      </div>
    </div>
  )
}

import type { LLMAdapter, Provider } from "./index"
import type { Chronicle } from "../types"
import type { PreparedImageInput, ProviderCapabilities } from "./context"
import type { SynthesisResult } from "./index"
import { prepareSynthesisInput } from "./context"
import { consumeSSE } from "./streamParser"
import type { ToolExecutor } from "./toolExecutor"

const API_URL = "https://api.anthropic.com/v1/messages"

export class AnthropicAdapter implements LLMAdapter {
  readonly provider: Provider = "anthropic"
  constructor(private key: string, public model: string) {}

  private headers() {
    return {
      "Content-Type": "application/json",
      "x-api-key": this.key,
      "anthropic-version": "2023-06-01",
      "anthropic-dangerous-direct-browser-access": "true",
    }
  }

  getCapabilities(): ProviderCapabilities {
    return {
      supportsVisionInput: true,
      supportsToolCalling: true,
      imageTransport: "public_url",
      preferredApi: "messages",
    }
  }

  async synthesize(chronicle: Chronicle, toolExecutor?: ToolExecutor): Promise<SynthesisResult> {
    try {
      return await this.requestWithSystemMessage(chronicle, false, undefined, undefined, toolExecutor)
    } catch (err) {
      if (isSystemMessageError(err)) {
        return await this.requestCombined(chronicle, false, undefined, undefined, toolExecutor)
      }
      throw err
    }
  }

  async synthesizeStream(
    chronicle: Chronicle,
    onChunk: (text: string) => void,
    signal?: AbortSignal,
    toolExecutor?: ToolExecutor
  ): Promise<SynthesisResult> {
    try {
      return await this.requestWithSystemMessage(chronicle, true, onChunk, signal, toolExecutor)
    } catch (err) {
      if (isSystemMessageError(err)) {
        return await this.requestCombined(chronicle, true, onChunk, signal, toolExecutor)
      }
      throw err
    }
  }

  private async requestWithSystemMessage(
    chronicle: Chronicle,
    stream: boolean,
    onChunk?: (text: string) => void,
    signal?: AbortSignal,
    toolExecutor?: ToolExecutor
  ): Promise<SynthesisResult> {
    const prepared = await prepareSynthesisInput(chronicle, this.getCapabilities(), toolExecutor?.getKeys())
    const tools = prepared.searchToolsEnabled ? prepared.availableTools.map(t => ({
      name: t.name,
      description: t.description,
      input_schema: t.parameters
    })) : undefined

    let messages: any[] = [{ role: "user", content: buildAnthropicContent(prepared.userPrompt, prepared.image) }]
    let inputMode = prepared.inputMode

    for (let i = 0; i < 7; i++) {
      const body: any = {
        model: this.model,
        max_tokens: 600,
        system: prepared.systemPrompt,
        messages,
        stream,
      }
      if (tools && tools.length > 0) {
        body.tools = tools
      }

      const res = await fetch(API_URL, {
        method: "POST",
        headers: this.headers(),
        body: JSON.stringify(body),
        signal,
      })

      if (!res.ok) {
        const err = await res.json().catch(() => ({}))
        throw new Error(`Anthropic error ${res.status}: ${JSON.stringify(err)}`)
      }

      if (stream) {
        const streamResult = await this.consumeAnthropicStreamWithTools(res, onChunk, signal)
        if (streamResult.toolCalls.length > 0 && toolExecutor) {
          messages.push({ role: "assistant", content: streamResult.assistantContent })
          const toolResultsContent = []
          for (const call of streamResult.toolCalls) {
            const result = await toolExecutor.executeTool(call.name, call.args)
            toolResultsContent.push({
              type: "tool_result",
              tool_use_id: call.id,
              content: JSON.stringify(result)
            })
          }
          messages.push({ role: "user", content: toolResultsContent })
          continue
        }
        return { text: streamResult.text, inputMode }
      } else {
        const data = await res.json() as any
        if (data.stop_reason === "tool_use" && toolExecutor) {
          messages.push({ role: "assistant", content: data.content })
          const toolResultsContent = []
          for (const block of data.content) {
            if (block.type === "tool_use") {
              const result = await toolExecutor.executeTool(block.name, block.input)
              toolResultsContent.push({
                type: "tool_result",
                tool_use_id: block.id,
                content: JSON.stringify(result)
              })
            }
          }
          messages.push({ role: "user", content: toolResultsContent })
          continue
        }
        return { text: data.content?.filter((c: any) => c.type === "text").map((c: any) => c.text).join("") ?? "", inputMode }
      }
    }

    return { text: "Tool calling limit reached.", inputMode }
  }

  private async requestCombined(
    chronicle: Chronicle,
    stream: boolean,
    onChunk?: (text: string) => void,
    signal?: AbortSignal,
    toolExecutor?: ToolExecutor
  ): Promise<SynthesisResult> {
    const prepared = await prepareSynthesisInput(chronicle, this.getCapabilities(), toolExecutor?.getKeys())
    const tools = prepared.searchToolsEnabled ? prepared.availableTools.map(t => ({
      name: t.name,
      description: t.description,
      input_schema: t.parameters
    })) : undefined

    let messages: any[] = [{ role: "user", content: buildAnthropicContent(prepared.combinedPrompt, prepared.image) }]
    let inputMode = prepared.inputMode

    for (let i = 0; i < 7; i++) {
      const body: any = {
        model: this.model,
        max_tokens: 600,
        messages,
        stream,
      }
      if (tools && tools.length > 0) {
        body.tools = tools
      }

      const res = await fetch(API_URL, {
        method: "POST",
        headers: this.headers(),
        body: JSON.stringify(body),
        signal,
      })

      if (!res.ok) {
        const err = await res.json().catch(() => ({}))
        throw new Error(`Anthropic error ${res.status}: ${JSON.stringify(err)}`)
      }

      if (stream) {
        const streamResult = await this.consumeAnthropicStreamWithTools(res, onChunk, signal)
        if (streamResult.toolCalls.length > 0 && toolExecutor) {
          messages.push({ role: "assistant", content: streamResult.assistantContent })
          const toolResultsContent = []
          for (const call of streamResult.toolCalls) {
            const result = await toolExecutor.executeTool(call.name, call.args)
            toolResultsContent.push({
              type: "tool_result",
              tool_use_id: call.id,
              content: JSON.stringify(result)
            })
          }
          messages.push({ role: "user", content: toolResultsContent })
          continue
        }
        return { text: streamResult.text, inputMode }
      } else {
        const data = await res.json() as any
        if (data.stop_reason === "tool_use" && toolExecutor) {
          messages.push({ role: "assistant", content: data.content })
          const toolResultsContent = []
          for (const block of data.content) {
            if (block.type === "tool_use") {
              const result = await toolExecutor.executeTool(block.name, block.input)
              toolResultsContent.push({
                type: "tool_result",
                tool_use_id: block.id,
                content: JSON.stringify(result)
              })
            }
          }
          messages.push({ role: "user", content: toolResultsContent })
          continue
        }
        return { text: data.content?.filter((c: any) => c.type === "text").map((c: any) => c.text).join("") ?? "", inputMode }
      }
    }

    return { text: "Tool calling limit reached.", inputMode }
  }

  private async consumeAnthropicStreamWithTools(
    res: Response,
    onChunk?: (text: string) => void,
    signal?: AbortSignal
  ): Promise<{ text: string, toolCalls: Array<{id: string, name: string, args: any}>, assistantContent: any[] }> {
    let accumulatedText = ""
    const toolCalls: Array<{id: string, name: string, args: any}> = []
    const assistantContent: any[] = []

    let currentToolId = ""
    let currentToolName = ""
    let currentToolInput = ""

    await consumeSSE(
      res,
      (data) => {
        try {
          const parsed = JSON.parse(data)
          if (parsed.type === "content_block_start") {
            if (parsed.content_block.type === "tool_use") {
              currentToolId = parsed.content_block.id
              currentToolName = parsed.content_block.name
              currentToolInput = ""
            }
          } else if (parsed.type === "content_block_delta") {
            if (parsed.delta.type === "text_delta") {
              accumulatedText += parsed.delta.text
              if (onChunk) onChunk(parsed.delta.text)
            } else if (parsed.delta.type === "input_json_delta") {
              currentToolInput += parsed.delta.partial_json
            }
          } else if (parsed.type === "content_block_stop") {
            if (currentToolId) {
              const args = JSON.parse(currentToolInput || "{}")
              toolCalls.push({ id: currentToolId, name: currentToolName, args })
              assistantContent.push({
                type: "tool_use",
                id: currentToolId,
                name: currentToolName,
                input: args
              })
              currentToolId = ""
            } else if (accumulatedText.length > 0 && assistantContent.length === 0) {
               // Only push text if it's a text block stopping
               assistantContent.push({ type: "text", text: accumulatedText })
            }
          }
        } catch {
          // Skip unparseable chunks
        }
      },
      signal
    )

    if (accumulatedText.length > 0 && assistantContent.length === 0) {
       assistantContent.push({ type: "text", text: accumulatedText })
    }

    return { text: accumulatedText, toolCalls, assistantContent }
  }
}

function buildAnthropicContent(text: string, image?: PreparedImageInput) {
  return [
    { type: "text", text },
    ...(image ? [toAnthropicImageBlock(image)] : []),
  ]
}

function toAnthropicImageBlock(image: PreparedImageInput) {
  if (image.transport === "public_url") {
    return {
      type: "image",
      source: {
        type: "url",
        url: image.url,
      },
    }
  }

  return {
    type: "image",
    source: {
      type: "base64",
      media_type: image.mimeType,
      data: image.data,
    },
  }
}

function isSystemMessageError(err: unknown): boolean {
  if (!(err instanceof Error)) return false
  const msg = err.message.toLowerCase()
  return msg.includes("system") && (msg.includes("not supported") || msg.includes("invalid"))
}

