import type { LLMAdapter, Provider } from "./index"
import type { Chronicle } from "../types"
import type { PreparedImageInput, ProviderCapabilities } from "./context"
import type { SynthesisResult } from "./index"
import { prepareSynthesisInput } from "./context"
import { consumeSSE } from "./streamParser"
import type { ToolExecutor } from "./toolExecutor"

const API_URL = "https://openrouter.ai/api/v1/chat/completions"

export class OpenRouterAdapter implements LLMAdapter {
  readonly provider: Provider = "openrouter"
  constructor(private key: string, public model: string) {}

  private headers() {
    return {
      "Content-Type": "application/json",
      Authorization: `Bearer ${this.key}`,
      "HTTP-Referer": typeof window !== "undefined" ? window.location.href : "https://ordinal-mind.com",
      "X-Title": "Ordinal Mind",
    }
  }

  getCapabilities(): ProviderCapabilities {
    return {
      supportsVisionInput: true,
      supportsToolCalling: false,
      imageTransport: "public_url",
      preferredApi: "chat_completions",
    }
  }

  async synthesize(chronicle: Chronicle, toolExecutor?: ToolExecutor): Promise<SynthesisResult> {
    try {
      return await this.request(chronicle, false, true, undefined, undefined, toolExecutor)
    } catch (err) {
      if (isSystemRoleError(err)) {
        return await this.request(chronicle, false, false, undefined, undefined, toolExecutor)
      }
      throw err
    }
  }

  async synthesizeStream(
    chronicle: Chronicle,
    onChunk: (text: string) => void,
    signal?: AbortSignal,
    toolExecutor?: ToolExecutor
  ): Promise<SynthesisResult> {
    try {
      return await this.request(chronicle, true, true, onChunk, signal, toolExecutor)
    } catch (err) {
      if (isSystemRoleError(err)) {
        return await this.request(chronicle, true, false, onChunk, signal, toolExecutor)
      }
      throw err
    }
  }

  private async request(
    chronicle: Chronicle,
    stream: boolean,
    useSystemRole: boolean,
    onChunk?: (text: string) => void,
    signal?: AbortSignal,
    toolExecutor?: ToolExecutor
  ): Promise<SynthesisResult> {
    const prepared = await prepareSynthesisInput(chronicle, this.getCapabilities(), toolExecutor?.getKeys())
    const tools = prepared.searchToolsEnabled ? prepared.availableTools.map(t => ({
      type: "function",
      function: {
        name: t.name,
        description: t.description,
        parameters: t.parameters
      }
    })) : undefined

    let messages: any[] = useSystemRole
      ? [
          { role: "system", content: prepared.systemPrompt },
          {
            role: "user",
            content: buildOpenRouterContent(prepared.userPrompt, prepared.image),
          },
        ]
      : [
          {
            role: "user",
            content: buildOpenRouterContent(prepared.combinedPrompt, prepared.image),
          },
        ]

    let inputMode = prepared.inputMode

    for (let i = 0; i < 7; i++) {
      const body: any = {
        model: this.model,
        max_tokens: 600,
        messages,
        stream,
      }
      if (tools && tools.length > 0) {
        body.tools = tools
      }

      const res = await fetch(API_URL, {
        method: "POST",
        headers: this.headers(),
        body: JSON.stringify(body),
        signal,
      })

      if (!res.ok) {
        const err = await res.json().catch(() => ({}))
        throw new Error(`OpenRouter error ${res.status}: ${JSON.stringify(err)}`)
      }

      if (stream) {
        const streamResult = await this.consumeOpenRouterStreamWithTools(res, onChunk, signal)
        if (streamResult.toolCalls.length > 0 && toolExecutor) {
          messages.push({ role: "assistant", tool_calls: streamResult.toolCalls.map(c => ({
            id: c.id,
            type: "function",
            function: { name: c.name, arguments: JSON.stringify(c.args) }
          }))})

          for (const call of streamResult.toolCalls) {
            const result = await toolExecutor.executeTool(call.name, call.args)
            messages.push({
              role: "tool",
              tool_call_id: call.id,
              name: call.name,
              content: JSON.stringify(result)
            })
          }
          continue
        }
        return { text: streamResult.text, inputMode }
      } else {
        const data = await res.json() as any
        const message = data.choices?.[0]?.message
        if (message?.tool_calls && toolExecutor) {
          messages.push(message)
          for (const call of message.tool_calls) {
             const args = JSON.parse(call.function.arguments)
             const result = await toolExecutor.executeTool(call.function.name, args)
             messages.push({
                role: "tool",
                tool_call_id: call.id,
                name: call.function.name,
                content: JSON.stringify(result)
             })
          }
          continue
        }
        return { text: message?.content ?? "", inputMode }
      }
    }

    return { text: "Tool calling limit reached.", inputMode }
  }

  private async consumeOpenRouterStreamWithTools(
    res: Response,
    onChunk?: (text: string) => void,
    signal?: AbortSignal
  ): Promise<{ text: string, toolCalls: Array<{id: string, name: string, args: any}> }> {
    let accumulatedText = ""
    const toolCallsMap: Record<number, {id: string, name: string, argsStr: string}> = {}

    await consumeSSE(
      res,
      (data) => {
        try {
          if (data === "[DONE]") return
          const parsed = JSON.parse(data)

          if (parsed.error) {
            console.error("[OpenRouter] mid-stream error:", parsed.error)
            return
          }

          const delta = parsed.choices?.[0]?.delta

          if (delta?.content) {
            accumulatedText += delta.content
            if (onChunk) onChunk(delta.content)
          }

          if (delta?.tool_calls) {
            for (const call of delta.tool_calls) {
              const index = call.index
              if (!toolCallsMap[index]) {
                toolCallsMap[index] = { id: call.id, name: call.function?.name ?? "", argsStr: "" }
              }
              if (call.function?.arguments) {
                toolCallsMap[index].argsStr += call.function.arguments
              }
            }
          }
        } catch {
          // Skip unparseable chunks
        }
      },
      signal
    )

    const toolCalls = Object.values(toolCallsMap).map(tc => {
      try {
        return { id: tc.id, name: tc.name, args: JSON.parse(tc.argsStr || "{}") }
      } catch {
        return { id: tc.id, name: tc.name, args: {} }
      }
    })

    return { text: accumulatedText, toolCalls }
  }
}

function buildOpenRouterContent(text: string, image?: PreparedImageInput) {
  if (!image) return text

  return [
    { type: "text", text },
    {
      type: "image_url",
      image_url: {
        url:
          image.transport === "public_url"
            ? image.url
            : `data:${image.mimeType};base64,${image.data}`,
      },
    },
  ]
}

function isSystemRoleError(err: unknown): boolean {
  if (!(err instanceof Error)) return false
  const msg = err.message.toLowerCase()
  return msg.includes("system") && (msg.includes("not supported") || msg.includes("invalid"))
}

import type { SearchProvider, SearchToolResult } from "./types"

export const braveProvider: SearchProvider = {
  name: "web_search",
  execute: async (args, config) => {
    const query = args.query as string | undefined
    if (!query) {
      return { tool_name: "web_search", results: [], error: "Missing query" }
    }

    if (!config.apiKey) {
      // In a real implementation, we could fallback to the scraping approach here
      // But for this phase, we require an API key
      return { tool_name: "web_search", results: [], error: "Brave API key not configured" }
    }

    try {
      const res = await fetch(`https://api.search.brave.com/res/v1/web/search?q=${encodeURIComponent(query)}&count=3`, {
        headers: {
          "Accept": "application/json",
          "X-Subscription-Token": config.apiKey,
        },
      })

      if (!res.ok) {
        throw new Error(`Brave API error: ${res.status}`)
      }

      const data = await res.json()
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const webResults = data.web?.results || []

      return {
        tool_name: "web_search",
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        results: webResults.map((r: any) => ({
          title: r.title,
          url: r.url,
          content: r.description,
          published_date: r.age,
        })),
      }
    } catch (e) {
      return { tool_name: "web_search", results: [], error: e instanceof Error ? e.message : String(e) }
    }
  },
}

import type { SearchProvider, SearchToolResult } from "./types"

export const coingeckoProvider: SearchProvider = {
  name: "market_context",
  execute: async (args) => {
    const coinId = args.coin_id as string | undefined
    if (!coinId) {
      return { tool_name: "market_context", results: [], error: "Missing coin_id" }
    }

    try {
      // CoinGecko public API is free and doesn't require a key, but has strict rate limits.
      // E.g., for bitcoin: /simple/price?ids=bitcoin&vs_currencies=usd&include_market_cap=true&include_24hr_vol=true&include_24hr_change=true&include_last_updated_at=true
      const url = `https://api.coingecko.com/api/v3/coins/${encodeURIComponent(coinId)}?localization=false&tickers=false&market_data=true&community_data=false&developer_data=false&sparkline=false`
      const res = await fetch(url)

      if (!res.ok) {
        throw new Error(`CoinGecko API error: ${res.status}`)
      }

      const data = await res.json()

      const marketData = data.market_data
      const content = `Market Data for ${data.name} (${data.symbol.toUpperCase()}):
- Current Price: $${marketData.current_price.usd}
- Market Cap: $${marketData.market_cap.usd}
- 24h Volume: $${marketData.total_volume.usd}
- 24h Change: ${marketData.price_change_percentage_24h}%
- All Time High: $${marketData.ath.usd} (on ${marketData.ath_date.usd})`

      return {
        tool_name: "market_context",
        results: [
          {
            title: `${data.name} Market Context`,
            url: `https://www.coingecko.com/en/coins/${data.id}`,
            content: content,
          }
        ],
      }
    } catch (e) {
      return { tool_name: "market_context", results: [], error: e instanceof Error ? e.message : String(e) }
    }
  },
}

import type { SearchProvider, SearchToolResult } from "./types"

export const exaProvider: SearchProvider = {
  name: "deep_research",
  execute: async (args, config) => {
    const query = args.query as string | undefined
    if (!query) {
      return { tool_name: "deep_research", results: [], error: "Missing query" }
    }

    if (!config.apiKey) {
      return { tool_name: "deep_research", results: [], error: "Exa API key not configured" }
    }

    try {
      const res = await fetch("https://api.exa.ai/search", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": config.apiKey,
        },
        body: JSON.stringify({
          query,
          numResults: 2,
          contents: { text: { maxCharacters: 4000 } },
        }),
      })

      if (!res.ok) {
        throw new Error(`Exa API error: ${res.status}`)
      }

      const data = await res.json()
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const results = data.results || []

      return {
        tool_name: "deep_research",
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        results: results.map((r: any) => ({
          title: r.title,
          url: r.url,
          content: r.text || r.summary || "",
          published_date: r.publishedDate,
        })),
      }
    } catch (e) {
      return { tool_name: "deep_research", results: [], error: e instanceof Error ? e.message : String(e) }
    }
  },
}

import type { SearchProvider, SearchToolResult } from "./types"

export const perplexityProvider: SearchProvider = {
  name: "synthesized_search",
  execute: async (args, config) => {
    const question = args.question as string | undefined
    if (!question) {
      return { tool_name: "synthesized_search", results: [], error: "Missing question" }
    }

    if (!config.apiKey) {
      return { tool_name: "synthesized_search", results: [], error: "Perplexity API key not configured" }
    }

    try {
      const res = await fetch("https://api.perplexity.ai/chat/completions", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${config.apiKey}`,
        },
        body: JSON.stringify({
          model: "sonar",
          messages: [
            { role: "system", content: "You are a research assistant. Provide a concise, factual answer based on web search. Cite sources." },
            { role: "user", content: question },
          ],
        }),
      })

      if (!res.ok) {
        throw new Error(`Perplexity API error: ${res.status}`)
      }

      const data = await res.json()
      const answer = data.choices?.[0]?.message?.content || ""

      // Attempt to extract citations if present (Perplexity returns citations in a specific format)
      // For simplicity, we just return the full text block

      return {
        tool_name: "synthesized_search",
        results: [
          {
            content: answer,
          }
        ],
      }
    } catch (e) {
      return { tool_name: "synthesized_search", results: [], error: e instanceof Error ? e.message : String(e) }
    }
  },
}

import type { SearchProvider, SearchToolResult } from "./types"

export const serpapiProvider: SearchProvider = {
  name: "public_interest",
  execute: async (args, config) => {
    const keyword = args.keyword as string | undefined
    if (!keyword) {
      return { tool_name: "public_interest", results: [], error: "Missing keyword" }
    }

    if (!config.apiKey) {
      return { tool_name: "public_interest", results: [], error: "SerpApi key not configured" }
    }

    try {
      console.log(`[SerpApi] Fetching trends for: ${keyword}`)
      const url = `https://serpapi.com/search.json?engine=google_trends&q=${encodeURIComponent(keyword)}&api_key=${config.apiKey}`
      const res = await fetch(url)

      if (!res.ok) {
        console.error(`[SerpApi] HTTP error: ${res.status}`)
        throw new Error(`SerpApi error: ${res.status}`)
      }

      const data = await res.json()
      console.log(`[SerpApi] Data received:`, data)
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const timeline = data.interest_over_time?.timeline_data || []

      if (timeline.length === 0) {
         return {
           tool_name: "public_interest",
           results: [{ content: `No trend data found for "${keyword}".` }]
         }
      }

      // Summarize the trend data to avoid passing huge payloads
      // Just extract the latest data point and maybe the max
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const values = timeline.map((d: any) => ({
        date: d.date,
        // Values usually come as arrays because of multiple keywords, here we assume one
        value: parseInt(d.values[0].extracted_value)
      }))

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const maxPoint = values.reduce((max: any, p: any) => p.value > max.value ? p : max, values[0])
      const currentPoint = values[values.length - 1]

      const content = `Google Trends data for "${keyword}":
- Current interest (relative, 0-100): ${currentPoint.value} (on ${currentPoint.date})
- Peak interest in the past year: ${maxPoint.value} (on ${maxPoint.date})
Analysis: The interest is currently at ${currentPoint.value}% of its peak.`

      return {
        tool_name: "public_interest",
        results: [
          {
            title: `Google Trends: ${keyword}`,
            url: `https://trends.google.com/trends/explore?q=${encodeURIComponent(keyword)}`,
            content: content,
          }
        ],
      }
    } catch (e) {
      return { tool_name: "public_interest", results: [], error: e instanceof Error ? e.message : String(e) }
    }
  },
}

import type { SearchProvider, SearchToolResult } from "./types"

export const serpapiSearchProvider: SearchProvider = {
  name: "web_search",
  execute: async (args, config) => {
    const query = args.query as string | undefined
    if (!query) {
      return { tool_name: "web_search", results: [], error: "Missing query" }
    }

    if (!config.apiKey) {
      return { tool_name: "web_search", results: [], error: "SerpApi key not configured" }
    }

    try {
      console.log(`[SerpApiSearch] Searching for: ${query}`)
      const url = `https://serpapi.com/search.json?engine=google&q=${encodeURIComponent(query)}&api_key=${config.apiKey}`
      const res = await fetch(url)

      if (!res.ok) {
        console.error(`[SerpApiSearch] HTTP error: ${res.status}`)
        throw new Error(`SerpApi error: ${res.status}`)
      }

      const data = await res.json()
      console.log(`[SerpApiSearch] Data received:`, data)

      interface SerpApiOrganicResult {
        title: string
        link: string
        snippet: string
      }

      const results = (data.organic_results || []).slice(0, 5).map((r: SerpApiOrganicResult) => ({
        title: r.title,
