      }
    } catch (e) {
      return { tool_name: "web_search", results: [], error: e instanceof Error ? e.message : String(e) }
    }
  },
}

import { braveProvider } from "./searchProviders/brave"
import { exaProvider } from "./searchProviders/exa"
import { perplexityProvider } from "./searchProviders/perplexity"
import { coingeckoProvider } from "./searchProviders/coingecko"
import { serpapiProvider } from "./searchProviders/serpapi"
import { serpapiSearchProvider } from "./searchProviders/serpapiSearch"
import type { SearchToolResult, SearchProviderConfig } from "./searchProviders/types"

const PROVIDERS = {
  web_search: braveProvider,
  deep_research: exaProvider,
  synthesized_search: perplexityProvider,
  market_context: coingeckoProvider,
  public_interest: serpapiProvider,
}

export interface ResearchLog {
  id: string
  tool: string
  args: any
  status: "running" | "done" | "error"
  result?: string
  error?: string
}

export interface ResearchKeys {
  braveSearchApiKey?: string
  exaApiKey?: string
  perplexityApiKey?: string
  serpapiApiKey?: string
}

export class ToolExecutor {
  private callCount = 0
  private maxCalls = 6
  private keys: ResearchKeys
  private onLog?: (log: ResearchLog) => void

  constructor(keys: ResearchKeys, onLog?: (log: ResearchLog) => void) {
    this.keys = keys
    this.onLog = onLog
  }

  public getKeys(): ResearchKeys {
    return this.keys
  }

  async executeTool(toolName: string, args: Record<string, unknown>): Promise<SearchToolResult> {
    const id = Math.random().toString(36).substring(2, 9)

    if (this.callCount >= this.maxCalls) {
      const error = "Maximum tool call limit reached."
      this.onLog?.({ id, tool: toolName, args, status: "error", error })
      return { tool_name: toolName, results: [], error }
    }

    this.callCount++
    console.log(`[ToolExecutor] Executing ${toolName} (Call ${this.callCount}/${this.maxCalls})`, args)
    this.onLog?.({ id, tool: toolName, args, status: "running" })

    let provider = Object.values(PROVIDERS).find(p => p.name === toolName)

    // Fallback logic for web_search
    if (toolName === "web_search" && !this.keys.braveSearchApiKey && this.keys.serpapiApiKey) {
      provider = serpapiSearchProvider
    }

    if (!provider) {
      const error = `Unknown tool: ${toolName}`
      this.onLog?.({ id, tool: toolName, args, status: "error", error })
      return { tool_name: toolName, results: [], error }
    }

    const config = this.getConfigForTool(toolName)
    try {
      const result = await provider.execute(args, config)

      if (result.error) {
        this.onLog?.({ id, tool: toolName, args, status: "error", error: result.error })
      } else {
        const resultSummary = result.results.map(r => r.title || (r.content ? (r.content.substring(0, 50) + "...") : "No content")).join(", ")
        this.onLog?.({ id, tool: toolName, args, status: "done", result: resultSummary })
      }

      return result
    } catch (e) {
      const error = String(e)
      console.error(`[ToolExecutor] Error executing ${toolName}:`, e)
      this.onLog?.({ id, tool: toolName, args, status: "error", error })
      return { tool_name: toolName, results: [], error }
    }
  }


  private getConfigForTool(toolName: string): SearchProviderConfig {
    switch (toolName) {
      case "web_search":
        return { apiKey: this.keys.braveSearchApiKey || this.keys.serpapiApiKey }
      case "deep_research":
        return { apiKey: this.keys.exaApiKey }
      case "synthesized_search":
        return { apiKey: this.keys.perplexityApiKey }
      case "public_interest":
        return { apiKey: this.keys.serpapiApiKey }
      case "market_context":
        return {} // CoinGecko is free
      default:
        return {}
    }
  }
}

import type { SocialMention, SourceCatalogItem } from "../../../app/lib/types"
import type { MentionProviderContext, MentionProviderResult } from "./types"
import { recordAttempt } from "./types"

export async function fetchGoogleTrendsMacro(
  context: MentionProviderContext,
  fetchImpl: typeof fetch = fetch
): Promise<MentionProviderResult> {
  const query = context.collectionName ?? context.fullLabel ?? context.itemName ?? context.inscriptionId
  if (!query) {
    recordAttempt(context.diagnostics, {
      query: "unknown",
      outcome: "skipped",
      detail: "No collection or inscription query available for Google Trends lookup.",
    })
    return {
      mentions: [],
      sourceCatalog: [{
        source_type: "google_trends_macro_attention",
        url_or_ref: "https://trends.google.com/trending",
        trust_level: "public_social",
        fetched_at: new Date().toISOString(),
        partial: true,
        detail: "Skipped Trends lookup because no query term was available.",
      }],
    }
  }

  const result = await fetchInterestScore(query, fetchImpl)
  if (!result.ok) {
    recordAttempt(context.diagnostics, {
      query,
      outcome: result.reason === "http_non_ok" ? "non_ok" : "fetch_failed",
      status: result.status,
      detail: result.detail,
    })
    context.diagnostics?.notes.push(`Google Trends unavailable for "${query}": ${result.detail}`)
    return {
      mentions: [],
      sourceCatalog: [{
        source_type: "google_trends_macro_attention",
        url_or_ref: "https://trends.google.com/trending",
        trust_level: "public_social",
        fetched_at: new Date().toISOString(),
        partial: true,
        detail: `Lookup failed for "${query}" (${result.detail}).`,
      }],
    }
  }

  const nowIso = new Date().toISOString()
  const mention: SocialMention = {
    platform: "google_trends",
    provider: "google_trends",
    canonical_url: `https://trends.google.com/trends/explore?q=${encodeURIComponent(query)}`,
    title: `Google search interest for "${query}"`,
    excerpt: `Annual attention summary: ${result.score1y}/100`,
    text: `Google Trends macro attention for ${query} over time:\n- Last 7 Days: ${result.score7d}/100\n- Last 30 Days: ${result.score30d}/100\n- Last 90 Days: ${result.score90d}/100\n- 1 Year: ${result.score1y}/100`,
    published_at: nowIso,
    discovered_at: nowIso,
    scope: "collection_level",
    match_type: "collection_only",
    provider_confidence: Math.max(0.1, Math.min(1, result.score1y / 100)),
  }

  recordAttempt(context.diagnostics, {
    query,
    outcome: "query_completed",
    result_count: 1,
    detail: `Attention scores (7d: ${result.score7d}, 30d: ${result.score30d}, 90d: ${result.score90d}, 1y: ${result.score1y})`,
  })

  const sourceCatalog: SourceCatalogItem[] = [{
    source_type: "google_trends_macro_attention",
    url_or_ref: mention.canonical_url,
    trust_level: "public_social",
    fetched_at: new Date().toISOString(),
    partial: false,
    detail: `Macro attention scores (7d: ${result.score7d}, 30d: ${result.score30d}, 90d: ${result.score90d}, 1y: ${result.score1y}) for "${query}".`,
  }]

  return { mentions: [mention], sourceCatalog }
}

async function fetchInterestScore(
  query: string,
  fetchImpl: typeof fetch
): Promise<
  | { ok: true; score7d: number; score30d: number; score90d: number; score1y: number }
  | { ok: false; reason: "http_non_ok" | "fetch_failed"; status?: number; detail: string }
> {
  const exploreReq = {
    comparisonItem: [{ keyword: query, geo: "", time: "today 12-m" }],
    category: 0,
    property: "",
  }

  let cookieHeader = ""
  try {
    const homeRes = await fetchImpl("https://trends.google.com/trends/", {
      headers: trendsHeaders(),
      signal: AbortSignal.timeout(5000),
    })
    const setCookie = homeRes.headers.get("set-cookie")
    if (setCookie) {
      const nidMatch = setCookie.match(/NID=[^;]+/)
      if (nidMatch) {
        cookieHeader = nidMatch[0]
      }
    }
  } catch (error) {
    // best effort
  }

  let exploreRes: Response
  try {
    const url = new URL("https://trends.google.com/trends/api/explore")
    url.searchParams.set("hl", "en-US")
    url.searchParams.set("tz", "0")
    url.searchParams.set("req", JSON.stringify(exploreReq))
    exploreRes = await fetchImpl(url.toString(), {
      headers: {
        ...trendsHeaders(),
        ...(cookieHeader ? { Cookie: cookieHeader } : {}),
      },
      signal: AbortSignal.timeout(7000),
    })
  } catch (error) {
    return {
      ok: false,
      reason: "fetch_failed",
      detail: error instanceof Error ? error.message : String(error),
    }
  }

  if (!exploreRes.ok) {
    return {
      ok: false,
      reason: "http_non_ok",
      status: exploreRes.status,
      detail: `explore endpoint returned HTTP ${exploreRes.status}`,
    }
  }

  let explorePayload: Record<string, unknown>
  try {
    explorePayload = parseXssiJson(await exploreRes.text())
  } catch (error) {
    return {
      ok: false,
      reason: "fetch_failed",
      detail: error instanceof Error ? error.message : String(error),
    }
  }

  const widgets = Array.isArray(explorePayload.widgets) ? explorePayload.widgets : []
  const timeseriesWidget = widgets.find((widget) => {
    if (!widget || typeof widget !== "object") return false
    const id = (widget as Record<string, unknown>).id
    return typeof id === "string" && id.toUpperCase().includes("TIMESERIES")
  }) as Record<string, unknown> | undefined

  if (!timeseriesWidget) {
    return {
      ok: false,
      reason: "fetch_failed",
      detail: "explore response had no timeseries widget",
    }
  }

  const token = typeof timeseriesWidget.token === "string" ? timeseriesWidget.token : null
  const request = timeseriesWidget.request
  if (!token || !request || typeof request !== "object") {
    return {
      ok: false,
      reason: "fetch_failed",
      detail: "timeseries widget did not expose token/request",
    }
  }

  let timelineRes: Response
  try {
    const url = new URL("https://trends.google.com/trends/api/widgetdata/multiline")
    url.searchParams.set("hl", "en-US")
    url.searchParams.set("tz", "0")
    url.searchParams.set("req", JSON.stringify(request))
    url.searchParams.set("token", token)
    timelineRes = await fetchImpl(url.toString(), {
      headers: {
        ...trendsHeaders(),
        ...(cookieHeader ? { Cookie: cookieHeader } : {}),
      },
      signal: AbortSignal.timeout(7000),
    })
  } catch (error) {
    return {
      ok: false,
      reason: "fetch_failed",
      detail: error instanceof Error ? error.message : String(error),
    }
  }

  if (!timelineRes.ok) {
    return {
      ok: false,
      reason: "http_non_ok",
      status: timelineRes.status,
      detail: `timeline endpoint returned HTTP ${timelineRes.status}`,
    }
  }

  let timelinePayload: Record<string, unknown>
  try {
    timelinePayload = parseXssiJson(await timelineRes.text())
  } catch (error) {
    return {
      ok: false,
      reason: "fetch_failed",
      detail: error instanceof Error ? error.message : String(error),
    }
  }

  const defaultObj = asRecord(timelinePayload.default)
  const timelineData = defaultObj && Array.isArray(defaultObj.timelineData)
    ? defaultObj.timelineData
    : []
  const points = timelineData
    .map((point) => {
      const values = asRecord(point as Record<string, unknown>)?.value
      if (!Array.isArray(values) || values.length === 0) return null
      const score = typeof values[0] === "number" ? values[0] : Number(values[0])
      return Number.isFinite(score) ? Math.max(0, Math.min(100, score)) : null
    })
    .filter((value): value is number => value !== null)

  if (points.length === 0) {
    return { ok: true, score7d: 0, score30d: 0, score90d: 0, score1y: 0 }
  }

  // today 12-m returns roughly 52 data points (weekly)
  const calcAverage = (arr: number[], count: number) => {
    const window = arr.slice(-Math.min(arr.length, Math.max(1, count)))
    if (window.length === 0) return 0
    return Math.round(window.reduce((sum, value) => sum + value, 0) / window.length)
  }

  const score7d = calcAverage(points, 1) // last 1 week
  const score30d = calcAverage(points, 4) // last 4 weeks (~1 month)
  const score90d = calcAverage(points, 13) // last 13 weeks (~3 months)
  const score1y = calcAverage(points, points.length) // all points (up to 52)

  return { ok: true, score7d, score30d, score90d, score1y }
}

function parseXssiJson(text: string): Record<string, unknown> {
  const cleaned = text.replace(/^\)\]\}',?\n?/, "").trim()
  const parsed = JSON.parse(cleaned) as unknown
  if (!parsed || typeof parsed !== "object") {
    throw new Error("Invalid Trends JSON payload.")
  }
  return parsed as Record<string, unknown>
}

function trendsHeaders(): Record<string, string> {
  return {
    "Accept": "application/json,text/plain,*/*",
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
    "Referer": "https://trends.google.com/trending",
  }
}

function asRecord(value: unknown): Record<string, unknown> | null {
  return value && typeof value === "object" ? value as Record<string, unknown> : null
}

// Timeline builder — deterministic merge and chronological sort of all events.
// Same input + same upstream data = same output.

import type { ChronicleEvent, InscriptionMeta, UnisatEnrichment } from "../app/lib/types"
import type { SocialMention } from "../app/lib/types"
import type { EnrichedTransfer } from "./agents/mempool"

let _seq = 0
const uid = () => `ev_${Date.now()}_${_seq++}`

export function buildTimeline(
  meta: InscriptionMeta,
  transfers: EnrichedTransfer[],
  socialMentions: SocialMention[],
  unisatEnrichment?: UnisatEnrichment
): ChronicleEvent[] {
  const events: ChronicleEvent[] = []

  // Genesis event — always present
  events.push({
    id: uid(),
    timestamp: meta.genesis_timestamp,
    block_height: meta.genesis_block,
    event_type: "genesis",
    source: { type: "onchain", ref: meta.genesis_txid },
    description: `Inscribed at block ${meta.genesis_block} · sat #${meta.sat?.toLocaleString("en-US") ?? "0"}`,
    metadata: {
      sat: meta.sat,
      content_type: meta.content_type,
      genesis_fee: meta.genesis_fee,
      address: meta.genesis_owner_address ?? meta.owner_address,
    },
  })

  // Sat rarity context (only if non-common)
  if (meta.sat_rarity !== "common") {
    const charms = meta.charms ?? (unisatEnrichment?.inscription_info?.charms ?? [])
    events.push({
      id: uid(),
      timestamp: meta.genesis_timestamp,
      block_height: meta.genesis_block,
      event_type: "sat_context",
      source: { type: "onchain", ref: `sat:${meta.sat}` },
      description: `Sat rarity: ${meta.sat_rarity}${charms.length > 0 ? ` · Charms: ${charms.join(", ")}` : ""}`,
      metadata: { sat_rarity: meta.sat_rarity, charms },
    })
  }

  if (unisatEnrichment?.rarity) {
    const r = unisatEnrichment.rarity
    const traitCount = r.traits.length

    let desc = `${traitCount} trait${traitCount !== 1 ? "s" : ""} detected`
    if (r.rarity_rank != null && r.total_supply != null) {
      desc += ` · rarity rank #${r.rarity_rank} of ${r.total_supply.toLocaleString("en-US")}`
      if (r.rarity_percentile != null) {
        desc += ` (top ${r.rarity_percentile}%)`
      }
    }

    events.push({
      id: uid(),
      timestamp: meta.genesis_timestamp,
      block_height: meta.genesis_block,
      event_type: "trait_context",
      source: { type: "web", ref: "ordinals.com" },
      description: desc,
      metadata: {
        rarity_rank: r.rarity_rank,
        rarity_score: r.rarity_score,
        rarity_percentile: r.rarity_percentile,
        total_supply: r.total_supply,
        trait_count: traitCount,
      },
    })
  }

  // Collection link
  if (meta.collection) {
    events.push({
      id: uid(),
      timestamp: meta.genesis_timestamp,
      block_height: meta.genesis_block,
      event_type: "collection_link",
      source: { type: "onchain", ref: meta.collection.parent_inscription_id },
      description: `Part of collection: ${meta.collection.name ?? meta.collection.parent_inscription_id.substring(0, 12) + "..."}`,
      metadata: meta.collection,
    })
  }

  // Recursive references
  const refs = meta.recursive_refs ?? []
  for (const ref of refs) {
    events.push({
      id: uid(),
      timestamp: meta.genesis_timestamp,
      block_height: meta.genesis_block,
      event_type: "recursive_ref",
      source: { type: "onchain", ref },
      description: `Recursively references inscription ${ref.substring(0, 12)}...`,
      metadata: { referenced_id: ref },
    })
  }

  // Transfers and sales — using forward-tracked data with real price detection
  for (const t of transfers) {
    events.push({
      id: uid(),
      timestamp: t.confirmed_at ?? new Date(0).toISOString(),
      block_height: t.block_height,
      event_type: t.is_sale ? "sale" : "transfer",
      source: { type: "onchain", ref: t.tx_id },
      description: t.is_sale
        ? `Sold for ${t.value ? (t.value / 1e8).toFixed(8) : "—"} BTC · ${truncAddr(t.from_address)} → ${truncAddr(t.to_address)}`
        : `Transferred · ${truncAddr(t.from_address)} → ${truncAddr(t.to_address)}`,
      metadata: {
        from: t.from_address,
        to: t.to_address,
        sale_price_sats: t.is_sale ? t.value : undefined,
        postage_sats: t.postage_value,
        is_sale: t.is_sale,
        is_heuristic: t.is_sale, // signals price was detected by on-chain heuristic
        inputs: t.input_count,
        outputs: t.output_count,
      },
    })
  }

  // Social mentions
  for (const mention of socialMentions) {
    events.push({
      id: uid(),
      timestamp: mention.published_at,
      block_height: 0,
      event_type: "social_mention",
      source: { type: "web", ref: mention.canonical_url },
      description: `Mentioned by ${mention.author_handle} on ${mention.platform}`,
      payload: mention,
      metadata: {
        platform: mention.platform,
        scope: mention.scope,
        match_type: mention.match_type,
        canonical_url: mention.canonical_url,
        excerpt: mention.excerpt,
        author_handle: mention.author_handle,
        author_url: mention.author_url,
        published_at: mention.published_at,
        discovered_at: mention.discovered_at,
        provider_confidence: mention.provider_confidence,
        engagement: mention.engagement,
      },
    })
  }

  // Chronological sort — events without a real timestamp go to the end
  events.sort((a, b) => {
    const ta = new Date(a.timestamp).getTime()
    const tb = new Date(b.timestamp).getTime()
    if (ta === 0 && tb === 0) return 0
    if (ta === 0) return 1
    if (tb === 0) return -1
    return ta - tb
  })

  return events
}

const truncAddr = (addr: string) =>
  addr && addr !== "?"
    ? `${addr.substring(0, 8)}…${addr.substring(addr.length - 6)}`
    : "?"

function platformLabel(platform: SocialMention["platform"]): string {
  switch (platform) {
    case "nostr":
      return "Nostr"
    case "x":
      return "X"
    case "google_trends":
      return "Google Trends"
    default:
      return "Social"
  }
}
